import React from 'react';

const ScreenFour = ({ allergies, handleAllergyChange, handleOtherAllergyDetailsChange }) => {
  const allergyOptions = [
    "No, I don't have allergies issues",
    'Lactose intolerance',
    'Celiac disease',
    'Egg allergy',
    'Fish Allergy',
    'Nut allergy',
    'I experience other chronic conditions not listed here'
  ];

  const handleCheckboxChange = (event) => {
    const { value } = event.target;
    handleAllergyChange(value);
  };

  const handleTextareaChange = (event) => {
    handleOtherAllergyDetailsChange(event.target.value);
  };

  return (
    <div>
      <h2>Do you have any allergies or chronic conditions?</h2>
      <div className="form-group">
        {allergyOptions.map((allergy, index) => (
          <div key={index} className="checkbox-group">
            <label>
              <input
                type="checkbox"
                value={allergy}
                checked={allergies.selectedAllergies.includes(allergy)}
                onChange={handleCheckboxChange}
              />
              {allergy}
            </label>
          </div>
        ))}
        {allergies.selectedAllergies.includes('I experience other chronic conditions not listed here') && (
          <div className="form-group">
            <label htmlFor="otherAllergyDetails">Please specify:</label>
            <textarea
              id="otherAllergyDetails"
              name="otherAllergyDetails"
              value={allergies.otherAllergyDetails}
              onChange={handleTextareaChange}
            />
          </div>
        )}
      </div>
    </div>
  );
};

export default ScreenFour;
